class TestScan:
    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_scan_builds_payload(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"results": []}
        idx.scan(num_results=20, last_primary_key="pk-7")
        call = mock_req.call_args.kwargs
        assert call["method"] == "GET"
        assert call["url"].endswith("/scan")
        body = call["json"]
        assert body["num_results"] == 20
        assert body["last_primary_key"] == "pk-7"
        assert body["endpoint_name"] == "test-endpoint"

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_scan_without_last_primary_key_omits_field(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"results": []}
        idx.scan(num_results=10)
        body = mock_req.call_args.kwargs["json"]
        assert "last_primary_key" not in body


class TestScanIndexDeprecation:
    def test_scan_index_attribute_exists(self, vector_search_index_factory):
        # `deprecation` is mocked at import time so the decorator wraps the
        # method in a MagicMock — calling it doesn't reach the real `scan`.
        # We can still assert the attribute is present, which is what the
        # deprecation path is supposed to leave behind for back-compat.
        idx = vector_search_index_factory()
        assert hasattr(idx, "scan_index")
        assert callable(idx.scan_index)


class TestSimilaritySearch:
    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_query_text_path(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(columns=["id"], query_text="hello", disable_notice=True)
        body = mock_req.call_args.kwargs["json"]
        assert body["query_text"] == "hello"
        assert "query_vector" not in body

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_query_vector_path(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(columns=["id"], query_vector=[0.1, 0.2], disable_notice=True)
        body = mock_req.call_args.kwargs["json"]
        assert body["query_vector"] == [0.1, 0.2]
        assert "query_text" not in body

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_filters_as_string_uses_filter_string(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(columns=["id"], query_text="x", filters="a > 5", disable_notice=True)
        body = mock_req.call_args.kwargs["json"]
        assert body["filter_string"] == "a > 5"
        assert body["filters_json"] is None

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_filters_as_dict_serialized_to_json(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(
            columns=["id"],
            query_text="x",
            filters={"a": "b"},
            disable_notice=True,
        )
        body = mock_req.call_args.kwargs["json"]
        assert json.loads(body["filters_json"]) == {"a": "b"}
        assert body["filter_string"] is None

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_score_threshold_and_query_type_only_when_truthy(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(columns=["id"], query_text="x", disable_notice=True)
        body = mock_req.call_args.kwargs["json"]
        assert "score_threshold" not in body
        assert "query_type" not in body

        idx.similarity_search(
            columns=["id"],
            query_text="x",
            score_threshold=0.5,
            query_type="HYBRID",
            disable_notice=True,
        )
        body = mock_req.call_args.kwargs["json"]
        assert body["score_threshold"] == 0.5
        assert body["query_type"] == "HYBRID"

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_advanced_fts_fields_only_when_provided(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(columns=["id"], query_text="x", disable_notice=True)
        body = mock_req.call_args.kwargs["json"]
        assert "query_columns" not in body
        assert "sort_columns" not in body
        assert "facets" not in body

        idx.similarity_search(
            columns=["id"],
            query_text="x",
            query_columns=["title", "body"],
            sort_columns=["rating DESC"],
            facets=["brand", "category TOP 5"],
            disable_notice=True,
        )
        body = mock_req.call_args.kwargs["json"]
        assert body["query_columns"] == ["title", "body"]
        assert body["sort_columns"] == ["rating DESC"]
        assert body["facets"] == ["brand", "category TOP 5"]

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_columns_to_rerank_legacy_path_sets_reranker_block(self, mock_req, vector_search_index_factory, capsys):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(
            columns=["id"],
            query_text="x",
            columns_to_rerank=["text"],
            disable_notice=True,
        )
        body = mock_req.call_args.kwargs["json"]
        assert body["reranker"]["model"] == "databricks_reranker"
        assert body["reranker"]["model_type"] == "MODEL_TYPE_BASE"
        assert body["reranker"]["parameters"]["columns_to_rerank"] == ["text"]
        # First call prints the deprecation notice.
        out = capsys.readouterr().out
        assert "deprecated" in out.lower()

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_columns_to_rerank_deprecation_notice_only_once(self, mock_req, vector_search_index_factory, capsys):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(
            columns=["id"],
            query_text="x",
            columns_to_rerank=["text"],
            disable_notice=True,
        )
        capsys.readouterr()  # drain first warning
        idx.similarity_search(
            columns=["id"],
            query_text="x",
            columns_to_rerank=["text"],
            disable_notice=True,
        )
        assert capsys.readouterr().out == ""

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_reranker_arg_sets_reranker_block(self, mock_req, vector_search_index_factory, capsys):
        idx = vector_search_index_factory()
        mock_req.return_value = {"result": {"row_count": 0, "data_array": []}}
        idx.similarity_search(
            columns=["id"],
            query_text="x",
            reranker=DatabricksReranker(columns_to_rerank=["text"]),
            disable_notice=True,
        )
        body = mock_req.call_args.kwargs["json"]
        assert body["reranker"]["model"] == "databricks_reranker"
        assert body["reranker"]["parameters"]["columns_to_rerank"] == ["text"]
        # No deprecation notice for the new path.
        assert "deprecated" not in capsys.readouterr().out.lower()

    def test_both_columns_to_rerank_and_reranker_raises(self, vector_search_index_factory):
        idx = vector_search_index_factory()
        with pytest.raises(ValueError, match="cannot both be provided"):
            idx.similarity_search(
                columns=["id"],
                query_text="x",
                columns_to_rerank=["a"],
                reranker=DatabricksReranker(columns_to_rerank=["b"]),
                disable_notice=True,
            )

    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_pagination_accumulates_results(self, mock_req, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.side_effect = [
            {
                "result": {"row_count": 2, "data_array": [[1], [2]]},
                "next_page_token": "tok-1",
            },
            {
                "result": {"row_count": 1, "data_array": [[3]]},
                "next_page_token": None,
            },
        ]
        result = idx.similarity_search(columns=["id"], query_text="x", disable_notice=True)
        assert result["result"]["row_count"] == 3
        assert result["result"]["data_array"] == [[1], [2], [3]]
        assert "next_page_token" not in result


class TestWaitUntilReady:
    @patch("databricks.vector_search.index.time.sleep")
    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_polls_until_online(self, mock_req, _sleep, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.side_effect = [
            {"status": {"detailed_state": "PROVISIONING"}},
            {"status": {"detailed_state": "ONLINE_NO_PENDING_UPDATE"}},
        ]
        idx.wait_until_ready()
        assert mock_req.call_count == 2

    @patch("databricks.vector_search.index.time.sleep")
    @patch("databricks.vector_search.index.RequestUtils.issue_request")
    def test_raises_on_offline(self, mock_req, _sleep, vector_search_index_factory):
        idx = vector_search_index_factory()
        mock_req.return_value = {"status": {"detailed_state": "OFFLINE_FAILED"}}
        with pytest.raises(Exception, match="offline"):
            idx.wait_until_ready()


class TestGetIndexUrl:
    """Module-level `_get_index_url` URL routing."""

    def test_pat_only_returns_control_plane_url(self):
        url = _get_index_url(
            index_url="https://dp/idx",
            workspace_url="https://ws",
            index_name="cat.sch.idx",
            personal_access_token="pat",
            service_principal_client_id=None,
            service_principal_client_secret=None,
        )
        assert url == "https://ws/api/2.0/vector-search/indexes/cat.sch.idx"

    def test_sp_with_index_url_returns_index_url(self):
        url = _get_index_url(
            index_url="dp.example/idx",
            workspace_url="https://ws",
            index_name="cat.sch.idx",
            personal_access_token=None,
            service_principal_client_id="id",
            service_principal_client_secret="secret",
        )
        # add_https_if_missing was applied.
        assert url == "https://dp.example/idx"

    def test_missing_index_url_falls_back_to_control_plane(self):
        url = _get_index_url(
            index_url=None,
            workspace_url="https://ws",
            index_name="cat.sch.idx",
            personal_access_token=None,
            service_principal_client_id="id",
            service_principal_client_secret="secret",
        )
        assert url == "https://ws/api/2.0/vector-search/indexes/cat.sch.idx"


class TestTokenForRequest:
    """Cover the cache-hit branches of VectorSearchIndex._get_token_for_request."""

    def test_pat_branch_returns_pat(self, vector_search_index_factory):
        idx = vector_search_index_factory()
        idx.personal_access_token = "pat-value"
        assert idx._get_token_for_request() == "pat-value"

    def test_control_plane_cache_hit_returns_cached_token(self, vector_search_index_factory, workspace_url):
        idx = vector_search_index_factory()
        # Index URL contains workspace_url, so control_plane is auto-detected.
        idx.index_url = f"{workspace_url}/api/2.0/vector-search/indexes/cat.sch.idx"
        assert idx._get_token_for_request() == "cp-token"

    def test_write_cache_hit_returns_write_token(self, vector_search_index_factory):
        idx = vector_search_index_factory()
        idx.index_url = "https://dp/idx"  # not control plane
        assert idx._get_token_for_request(write=True) == "write-token"

    def test_read_cache_hit_returns_read_token(self, vector_search_index_factory):
        idx = vector_search_index_factory()
        idx.index_url = "https://dp/idx"  # not control plane
        assert idx._get_token_for_request() == "read-token"

    def test_explicit_control_plane_returns_cp_token(self, vector_search_index_factory):
        idx = vector_search_index_factory()
        idx.index_url = "https://dp/idx"  # not control plane in URL
        assert idx._get_token_for_request(control_plane=True) == "cp-token"

    def test_expired_token_triggers_refetch(self, vector_search_index_factory):
        idx = vector_search_index_factory()
        idx.index_url = "https://dp/idx"
        idx._read_oauth_token_expiry_ts = time.time() - 1  # expired
        with patch(
            "databricks.vector_search.utils.OAuthTokenUtils.get_oauth_token",
            return_value={"access_token": "fresh", "expires_in": 3600},
        ):
            assert idx._get_token_for_request() == "fresh"
